function buildCategoriesSelect() {
    let html = '';

    // Build the category select (first dropdown)
    html += "<select style=\"height: 1.8em !important\" id=\"categorySelect\" onchange='let category = this.value; const allOptions = document.querySelectorAll(\"#iconsSelect option\");allOptions.forEach(option => {option.disabled = true;option.style.display = \"none\";});const categoryOptions = document.querySelectorAll(\"#iconsSelect .\" + category );categoryOptions.forEach(option => {option.disabled = false;option.style.display = \"block\";})'>\n";
    html += '<option value="">-- Select Icon Category --</option>\n';
    for (let category in iconsObject) {
        html += `<option value="${category}">${capitalize(category.trim())}</option>\n`;
    }
    html += '</select>\n';
    return html;
}

//Flow `categoriesSelect` will hold html icon categories select snippet
flow.set("categoriesSelect", buildCategoriesSelect());

//build icons select
function buildIconsSelect() {
    let html = '';
    // Build the options select (second dropdown)
    html += '<select style=\"height: 1.8em !important\" id="iconsSelect" onchange="addToForm(this.id,this.value)">\n';
    html += '<option value="">-- Select Icon --</option>\n';
    for (let category in iconsObject) {
        const options = iconsObject[category].split(",");
        options.forEach(value => {
            html += `<option value="${value.trim()}" class="${category} hidden-option">${capitalize(value.trim())}</option>\n`;
        });
    }
    html += '</select>\n';

    return html;
}
//Flow `categoriesSelect` will hold html icons select snippet
flow.set("iconsSelect", buildIconsSelect());

