function toRadians(degrees) {
    return degrees * Math.PI / 180;
}

function toDegrees(radians) {
    return radians * 180 / Math.PI;
}

function calculateNewPosition(lat1, lon1, speed, heading, time) {
    const R = 6371000; // Earth's radius in meters

    // Convert latitude and longitude from degrees to radians
    const lat1Rad = toRadians(lat1);
    const lon1Rad = toRadians(lon1);

    // Convert heading to radians
    const headingRad = toRadians(heading);

    // Calculate the distance traveled
    const distance = speed * time;

    // Calculate the new latitude
    const lat2Rad = Math.asin(Math.sin(lat1Rad) * Math.cos(distance / R) + 
        Math.cos(lat1Rad) * Math.sin(distance / R) * Math.cos(headingRad));

    // Calculate the new longitude
    const lon2Rad = lon1Rad + Math.atan2(Math.sin(headingRad) * Math.sin(distance / R) * Math.cos(lat1Rad),
        Math.cos(distance / R) - Math.sin(lat1Rad) * Math.sin(lat2Rad));

    // Convert the new latitude and longitude back to degrees
    const lat2 = toDegrees(lat2Rad);
    const lon2 = toDegrees(lon2Rad);

    return { lat: lat2, lon: lon2 };
}
if ((object.speed > 0) && index !== -1) {
