'use strict'

// Update the quote
function updQuote(quote) {
    // Update the quote
    $('#quoteText').innerText = quote.body
    // and the author
    $('#quoteAuthor').innerText = quote.author
    // And the overall quote citation
    $('#quote').setAttribute('cite', quote.url)
}

// Listen for incoming messages from Node-RED
uibuilder.onChange('msg', function (msg) {
    // Make sure we only process quotes and ignore other messages.
    // Generally sensible to filter like this.
    if (msg.topic === 'getQuote') updQuote(msg.payload.quote)
})

